{
  "variables": [
    {
      "id": "trust",
      "label": "Trust in the Review System",
      "description": "The degree of confidence that merged code is correct, safe, and meets product requirements"
    },
    {
      "id": "layer1-automation",
      "label": "Layer 1: Automation (CI/LLM)",
      "description": "CI pipelines, coverage thresholds, adversarial LLM review, mutation testing — catches correctness and regressions before human review"
    },
    {
      "id": "layer2-behavioral",
      "label": "Layer 2: Behavioral Review",
      "description": "Structured walkthrough of observable product behaviors by a human reviewer acting as a user; catches UX failures, workflow gaps, and miscommunication"
    },
    {
      "id": "layer3-structural",
      "label": "Layer 3: Structural/Code Review",
      "description": "Mandatory line-by-line code review triggered by risk classification for high-consequence changes (auth, schema, infrastructure, API boundaries)"
    },
    {
      "id": "human-spec",
      "label": "Human Test Case Specification",
      "description": "Author-defined edge cases and failure modes that break the circular validation trap by separating specification (human) from implementation (AI)"
    },
    {
      "id": "author-curation",
      "label": "Author Walkthrough Curation",
      "description": "The author's control over which behaviors appear in the behavioral walkthrough, creating a systematic conflict of interest"
    },
    {
      "id": "diff-coverage",
      "label": "Diff-Coverage Automation",
      "description": "Automated reporting linking changed files to walkthrough items; flags uncovered changed files to make curation gaps visible"
    },
    {
      "id": "spot-checks",
      "label": "Random Spot Checks (~1-in-10)",
      "description": "Randomly selected routine changes that receive full structural review, keeping authors honest and reviewers code-literate"
    },
    {
      "id": "risk-classification",
      "label": "Risk Classification (CI-automated)",
      "description": "Automated or author-assigned categorization of change type that gates which review layers are triggered"
    },
    {
      "id": "social-contract",
      "label": "Social Contract / Explicit Agreement",
      "description": "Explicit negotiation among collaborators about review norms, roles, and expectations — not assumed but actively established"
    },
    {
      "id": "reviewer-engagement",
      "label": "Reviewer Engagement",
      "description": "Whether the reviewer actively performs verification versus rubber-stamping; a social/motivational variable that tooling cannot fully control"
    },
    {
      "id": "rubber-stamping",
      "label": "Rubber-Stamping Risk",
      "description": "The risk that reviewers approve without genuinely verifying, rendering the review layer a procedural fiction"
    },
    {
      "id": "implementation-knowledge",
      "label": "Implementation Knowledge Transfer",
      "description": "Reviewers developing understanding of how subsystems work at the code level; essential for bus-factor resilience"
    },
    {
      "id": "bus-factor",
      "label": "Bus Factor / Single Point of Failure",
      "description": "Organizational risk that only the author understands the implementation, making the system fragile to author departure or absence"
    },
    {
      "id": "serendipitous-discovery",
      "label": "Serendipitous Bug Discovery",
      "description": "Defects caught by a reviewer asking 'what happens if X?' while reading code — a class of discovery eliminated by pure behavioral review"
    },
    {
      "id": "circular-validation",
      "label": "Circular Validation Trap",
      "description": "AI writes both code and tests reflecting the same misunderstanding; automation alone cannot break this loop"
    },
    {
      "id": "formalization",
      "label": "Formal Specification (Phase 3)",
      "description": "Machine-checkable formal specifications of high-value behavioral properties, bootstrapped by the product's own formalization capabilities"
    },
    {
      "id": "process-drift",
      "label": "Process Drift Toward Automation-Only",
      "description": "Predicted degradation of the three-layer system within 6-12 months as walkthroughs compress, spot checks are skipped, and rubber-stamping dominates"
    },
    {
      "id": "walkthrough-freshness",
      "label": "Walkthrough Freshness / Staleness",
      "description": "Whether behavioral walkthrough items accurately reflect current product behavior; stale items are worse than no items"
    },
    {
      "id": "onboarding-artifact",
      "label": "Dual-Purpose Onboarding Artifact",
      "description": "The walkthrough serving simultaneously as a review queue and a permanent onboarding guide; a concrete deliverable beyond approval"
    }
  ],
  "edges": [
    {
      "from": "human-spec",
      "to": "circular-validation",
      "weight": -0.85,
      "mechanism": "Human specification of edge cases and failure modes separates spec from implementation, breaking the tautological loop where AI-generated tests only verify AI-generated code's own assumptions"
    },
    {
      "from": "human-spec",
      "to": "layer1-automation",
      "weight": 0.8,
      "mechanism": "Human-defined test cases are the input that gives Layer 1 automation meaningful coverage; without them, automation verifies only what the AI already believed to be true"
    },
    {
      "from": "layer1-automation",
      "to": "trust",
      "weight": 0.65,
      "mechanism": "CI, adversarial LLM review, and mutation testing provide evidence-based confidence in correctness and regression prevention — but trust is conditional on humans specifying the test cases"
    },
    {
      "from": "circular-validation",
      "to": "layer1-automation",
      "weight": -0.7,
      "mechanism": "When AI writes both code and tests, automation verifies a closed loop of shared misunderstanding rather than ground truth; the circular trap undermines the trustworthiness of passing CI"
    },
    {
      "from": "layer2-behavioral",
      "to": "trust",
      "weight": 0.6,
      "mechanism": "Behavioral review catches user-facing defects (UX failures, workflow gaps, miscommunication) that automation cannot detect; reviewer experience of the product as a user adds a trust dimension absent from code-level or automated checks"
    },
    {
      "from": "layer3-structural",
      "to": "trust",
      "weight": 0.75,
      "mechanism": "Mandatory code review for high-risk change types (auth, schema, infrastructure) catches security vulnerabilities, architectural decay, and race conditions that are invisible at the behavioral surface"
    },
    {
      "from": "author-curation",
      "to": "layer2-behavioral",
      "weight": -0.65,
      "mechanism": "The author controls what appears in the walkthrough; systematic omission of behaviors the author wishes to avoid scrutiny creates blind spots in behavioral coverage, undermining the layer's integrity"
    },
    {
      "from": "diff-coverage",
      "to": "author-curation",
      "weight": -0.7,
      "mechanism": "Automated linking of changed files to walkthrough items makes curation gaps visible; the author cannot silently omit changed behaviors without the omission appearing as a flagged uncovered file"
    },
    {
      "from": "spot-checks",
      "to": "author-curation",
      "weight": -0.6,
      "mechanism": "The possibility that any routine change may be selected for full structural review creates a deterrent against strategic omission; the author cannot predict which changes will be inspected"
    },
    {
      "from": "spot-checks",
      "to": "implementation-knowledge",
      "weight": 0.65,
      "mechanism": "Periodic full diff review on randomly selected routine changes incrementally builds reviewer implementation understanding even when Layer 3 is not formally triggered"
    },
    {
      "from": "spot-checks",
      "to": "process-drift",
      "weight": -0.7,
      "mechanism": "Mandatory spot checks are a primary countermeasure against drift; their absence is one of the three predicted preconditions for degradation to automation-only review within 6-12 months"
    },
    {
      "from": "risk-classification",
      "to": "layer3-structural",
      "weight": 0.85,
      "mechanism": "CI-automated or author-assigned risk classification is the trigger mechanism for Layer 3; changes to auth/, migrations/, and infrastructure configs route to mandatory code review"
    },
    {
      "from": "risk-classification",
      "to": "layer2-behavioral",
      "weight": 0.5,
      "mechanism": "Low-risk change classification routes changes to behavioral-only review; the classification determines which layer(s) apply, making classification integrity a precondition for appropriate oversight allocation"
    },
    {
      "from": "author-curation",
      "to": "risk-classification",
      "weight": -0.5,
      "mechanism": "Where risk classification is author-assigned rather than CI-automated, the same conflict of interest that affects walkthrough curation applies; authors may under-classify change risk to avoid triggering Layer 3"
    },
    {
      "from": "diff-coverage",
      "to": "risk-classification",
      "weight": 0.4,
      "mechanism": "Diff-coverage automation provides an external check on classification honesty by making the relationship between changed files and review coverage visible, partially mitigating author self-classification bias"
    },
    {
      "from": "social-contract",
      "to": "reviewer-engagement",
      "weight": 0.75,
      "mechanism": "Explicit negotiation of review norms — whether the reviewer wants to do behavioral verification, what counts as adequate spot-checking — establishes the motivational foundation that tooling cannot substitute"
    },
    {
      "from": "social-contract",
      "to": "process-drift",
      "weight": -0.7,
      "mechanism": "Without explicit social contract negotiation, assumed agreement degrades under velocity pressure; the document identifies this as one of three conditions whose absence predicts drift to automation-only review"
    },
    {
      "from": "reviewer-engagement",
      "to": "rubber-stamping",
      "weight": -0.9,
      "mechanism": "Genuine reviewer engagement — actually running the product, testing behaviors, flagging mismatches — is the direct inverse of rubber-stamping; engagement is the mechanism through which behavioral review produces value rather than procedural fiction"
    },
    {
      "from": "rubber-stamping",
      "to": "layer2-behavioral",
      "weight": -0.8,
      "mechanism": "If reviewers check boxes without testing, the behavioral layer provides the appearance of oversight without substance; rubber-stamping nullifies the defect-catching value of the entire layer"
    },
    {
      "from": "rubber-stamping",
      "to": "trust",
      "weight": -0.7,
      "mechanism": "Undetected rubber-stamping produces false trust — the review system appears to be functioning while providing no actual verification; this is the failure mode the system is most vulnerable to and least able to detect from the outside"
    },
    {
      "from": "layer3-structural",
      "to": "implementation-knowledge",
      "weight": 0.7,
      "mechanism": "Mandatory code review for high-risk changes and spot checks for routine changes are the primary mechanisms by which reviewers develop and maintain implementation-level understanding of subsystems"
    },
    {
      "from": "implementation-knowledge",
      "to": "bus-factor",
      "weight": -0.75,
      "mechanism": "When reviewers understand how subsystems are implemented, the team is less dependent on the author as the sole person capable of maintaining or debugging those subsystems"
    },
    {
      "from": "layer2-behavioral",
      "to": "implementation-knowledge",
      "weight": -0.5,
      "mechanism": "Behavioral review deliberately does not require reviewers to read implementation code; this scalability gain comes at the cost of implementation knowledge, which weakens over time if Layer 3 and spot checks do not compensate"
    },
    {
      "from": "layer2-behavioral",
      "to": "serendipitous-discovery",
      "weight": -0.8,
      "mechanism": "Behavioral review systematically eliminates the reviewer asking 'what happens if X?' while reading code; this class of defect discovery is an accepted loss of the behavioral-primary approach"
    },
    {
      "from": "layer3-structural",
      "to": "serendipitous-discovery",
      "weight": 0.6,
      "mechanism": "Mandatory code review for high-risk changes and random spot checks partially preserve serendipitous discovery for the change types where it is most consequential"
    },
    {
      "from": "walkthrough-freshness",
      "to": "layer2-behavioral",
      "weight": 0.8,
      "mechanism": "Stale walkthrough items — items that no longer match current product behavior — are described as worse than no items because they create the illusion of verification; freshness is a prerequisite for the behavioral layer's integrity"
    },
    {
      "from": "walkthrough-freshness",
      "to": "process-drift",
      "weight": -0.6,
      "mechanism": "Maintaining walkthrough freshness as a blocking condition on merge is a forcing function against drift; when freshness requirements are relaxed or ignored, the walkthrough compresses and the behavioral layer loses specificity"
    },
    {
      "from": "layer2-behavioral",
      "to": "onboarding-artifact",
      "weight": 0.7,
      "mechanism": "The dual-purpose model feeds verified walkthrough items into a permanent onboarding guide, giving behavioral review a concrete deliverable beyond approval that serves new users and documents product state"
    },
    {
      "from": "onboarding-artifact",
      "to": "implementation-knowledge",
      "weight": 0.4,
      "mechanism": "The onboarding guide partially compensates for the loss of implementation knowledge transfer by documenting what the product does and how to use it, though it does not substitute for code-level understanding"
    },
    {
      "from": "formalization",
      "to": "layer1-automation",
      "weight": 0.75,
      "mechanism": "Formal specifications of high-value behavioral properties shift those behaviors from manual walkthrough items to machine-checked CI properties, expanding automation's scope as product capabilities mature"
    },
    {
      "from": "formalization",
      "to": "layer2-behavioral",
      "weight": -0.4,
      "mechanism": "As formalization matures, walkthrough items for formalized behaviors are retired from manual verification to machine-checked properties, gradually reducing the scope of what behavioral review must cover manually"
    },
    {
      "from": "formalization",
      "to": "trust",
      "weight": 0.7,
      "mechanism": "Machine-checked proofs that implementations satisfy formal specifications provide stronger trust guarantees than behavioral testing or code review alone, growing stronger as the product's formalization capabilities mature"
    },
    {
      "from": "process-drift",
      "to": "trust",
      "weight": -0.85,
      "mechanism": "Drift toward automation-only review eliminates the behavioral and structural layers, leaving only CI as the trust mechanism; this removes the communication, UX defect-catching, and architectural oversight functions, producing a system that appears to function but has systematic blind spots"
    },
    {
      "from": "social-contract",
      "to": "spot-checks",
      "weight": 0.65,
      "mechanism": "Spot checks depend on explicit agreement about norms and accountability — without social contract establishing them as mandatory rather than aspirational, they are the first element to be skipped under velocity pressure"
    }
  ],
  "confounders": [
    {
      "id": "ai-velocity",
      "label": "AI-Assisted Development Velocity",
      "description": "The increased rate of change per unit time enabled by AI code generation, which simultaneously motivates the three-layer system and creates the pressure that causes it to degrade",
      "affectedEdges": [
        "author-curation->layer2-behavioral",
        "reviewer-engagement->rubber-stamping",
        "social-contract->process-drift",
        "spot-checks->process-drift"
      ]
    },
    {
      "id": "reviewer-fluency",
      "label": "Reviewer Library/Language Fluency",
      "description": "Whether the reviewer is fluent in the libraries and language features used in AI-generated code; low fluency makes traditional code review produce the appearance of review without substance, motivating the behavioral shift",
      "affectedEdges": [
        "layer3-structural->implementation-knowledge",
        "layer3-structural->serendipitous-discovery",
        "layer3-structural->trust"
      ]
    },
    {
      "id": "team-size",
      "label": "Team Size (Currently Two)",
      "description": "The system is explicitly designed for a two-person team; small team size concentrates the social contract negotiation, makes rubber-stamping relationship dynamics more acute, and makes bus factor risk more severe",
      "affectedEdges": [
        "social-contract->reviewer-engagement",
        "implementation-knowledge->bus-factor",
        "author-curation->risk-classification"
      ]
    },
    {
      "id": "product-maturity",
      "label": "Product/Formalization Maturity",
      "description": "How mature the product's own formalization capabilities are; this determines how quickly Phase 3 trust bootstrapping can expand machine-checked coverage and reduce dependence on manual behavioral review",
      "affectedEdges": [
        "formalization->layer1-automation",
        "formalization->layer2-behavioral",
        "formalization->trust"
      ]
    }
  ],
  "summary": "Trust in this system is not located in any single layer but is distributed across three interdependent mechanisms, each responsible for a distinct defect class: Layer 1 automation (correctness and regressions, trustworthy only when humans specify the test cases that break the circular validation trap), Layer 2 behavioral review (user-facing defects and communication, trustworthy only when reviewer engagement is genuine and walkthrough freshness is enforced), and Layer 3 structural review (security, architecture, and high-risk changes, triggered by risk classification and preserved by random spot checks). The critical insight is that trust is actively undermined at each layer by a specific conflict of interest or failure mode — circular validation corrupts Layer 1, author curation corrupts Layer 2, and risk classification manipulation corrupts Layer 3 — and the integrity mechanisms (human spec, diff-coverage automation, spot checks, social contract) are not optional enhancements but load-bearing preconditions for the trust each layer is supposed to provide. The system's most significant vulnerability is that none of these integrity mechanisms are self-enforcing: absent explicit social contract negotiation, mandatory spot check norms, and diff-coverage tooling, the document's own analysis predicts predictable degradation toward automation-only review within 6-12 months as velocity pressure systematically selects against the higher-friction layers. Trust, in this architecture, is therefore not an output of the system's structure but a function of active social maintenance — the three layers define where trust could be grounded, but the social contract determines whether it actually is."
}
